const fs = require('fs');
const loan = JSON.parse(fs.readFileSync('/var/folders/1q/vdr_cj816z314xnj3bp7w_wr0000gn/T/capture-loan_calculator-eerf64l6/loan_calculator/sample_inputs/loan_008.json'));

const principal = loan.principal;
const annual_rate_pct = loan.annual_rate_pct;
const term_months = loan.term_months;
const origination_fee = loan.origination_fee;

const monthly_rate = annual_rate_pct / 100 / 12;
let monthly_payment;

if (monthly_rate === 0) {
  monthly_payment = principal / term_months;
} else {
  const numerator = principal * monthly_rate * Math.pow(1 + monthly_rate, term_months);
  const denominator = Math.pow(1 + monthly_rate, term_months) - 1;
  monthly_payment = numerator / denominator;
}

monthly_payment = Math.round(monthly_payment * 100) / 100;

const total_interest = Math.round((monthly_payment * term_months - principal) * 100) / 100;
const total_paid = Math.round((principal + total_interest + origination_fee) * 100) / 100;

