perl -e '
use strict;
use warnings;
use JSON;

my $json_text = `cat /var/folders/1q/vdr_cj816z314xnj3bp7w_wr0000gn/T/capture-loan_calculator-eerf64l6/loan_calculator/sample_inputs/loan_008.json`;
my $loan = decode_json($json_text);

my $principal = $loan->{principal};
my $annual_rate_pct = $loan->{annual_rate_pct};
my $term_months = $loan->{term_months};
my $origination_fee = $loan->{origination_fee};

my $monthly_rate = $annual_rate_pct / 100 / 12;
my $monthly_payment;

if ($monthly_rate == 0) {
  $monthly_payment = $principal / $term_months;
} else {
  my $power = (1 + $monthly_rate) ** $term_months;
  $monthly_payment = $principal * $monthly_rate * $power / ($power - 1);
}

$monthly_payment = int($monthly_payment * 100 + 0.5) / 100;

my $total_interest = int(($monthly_payment * $term_months - $principal) * 100 + 0.5) / 100;
my $total_paid = int(($principal + $total_interest + $origination_fee) * 100 + 0.5) / 100;

my @discrepancies;

if ($monthly_payment != $loan->{stated_monthly_payment}) {
  push @discrepancies, {
    field => "monthly_payment",
    stated => $loan->{stated_monthly_payment},
    computed => $monthly_payment,
    delta => int(($monthly_payment - $loan->{stated_monthly_payment}) * 100 + 0.5) / 100
  };
}

if ($total_interest != $loan->{stated_total_interest}) {
  push @discrepancies, {
    field => "total_interest",
    stated => $loan->{stated_total_interest},
    computed => $total_interest,
    delta => int(($total_interest - $loan->{stated_total_interest}) * 100 + 0.5) / 100
  };
}

if ($total_paid != $loan->{stated_total_paid}) {
  push @discrepancies, {
    field => "total_paid",
    stated => $loan->{stated_total_paid},
    computed => $total_paid,
    delta => int(($total_paid - $loan->{stated_total_paid}) * 100 + 0.5) / 100
  };
}

my $result = {
  loan_id => $loan->{loan_id},
  lender => $loan->{lender},
  computed => {
    monthly_payment => $monthly_payment,
    total_interest => $total_interest,
    total_paid => $total_paid
  },
  discrepancies => \@discrepancies,
  valid => scalar(@discrepancies) == 0 ? JSON::true : JSON::false
};

open my $fh, ">", "/var/folders/1q/vdr_cj816z314xnj3bp7w_wr0000gn/T/capture-loan_calculator-eerf64l6/loan_calculator/output.json" or die;
print $fh encode_json($result);
close $fh;

print encode_json($result);
'
